// Authenticate to Vault
const vaultToken = await $http.request({
  url: 'http://127.0.0.1:8200/v1/auth/approle/login',
  method: 'POST',
  body: {
    role_id: $env.VAULT_ROLE_ID,     // Non-sensitive
    secret_id: $env.VAULT_SECRET_ID   // Rotates every hour
  }
});

// Fetch Silicon Flow key (encrypted at rest)
const secret = await $http.request({
  url: 'http://127.0.0.1:8200/v1/secret/data/silicon-flow',
  headers: { 'X-Vault-Token': vaultToken.data.auth.client_token }
});

const apiKey = secret.data.data.key; // Decrypted only in memory, never logged

